import jwt
from jwt import PyJWKClient

class JWTWrapper:
    def __init__(self, secret=None, public_key=None, jwks_url=None):
        self.secret = secret
        self.public_key = public_key
        self.jwks_url = jwks_url

    def decode_token(self, token):
        headers = jwt.get_unverified_header(token)
        alg = headers.get('alg')

        if alg == 'none':
            return jwt.decode(token, options={"verify_signature": False})

        if alg.startswith('HS'):
            return jwt.decode(token, self.secret, algorithms=[alg])

        if alg.startswith('RS') or alg.startswith('ES'):
            if self.jwks_url:
                jwks_client = PyJWKClient(self.jwks_url)
                signing_key = jwks_client.get_signing_key_from_jwt(token).key
                return jwt.decode(token, signing_key, algorithms=[alg])
            elif self.public_key:
                return jwt.decode(token, self.public_key, algorithms=[alg])

        raise ValueError("Unsupported algorithm or missing key information")

    def encode_token(self, payload, algorithm='HS256'):
        if algorithm.startswith('HS'):
            return jwt.encode(payload, self.secret, algorithm=algorithm)
        elif algorithm.startswith('RS') or algorithm.startswith('ES'):
            return jwt.encode(payload, self.public_key, algorithm=algorithm)
        elif algorithm == 'none':
            return jwt.encode(payload, key=None, algorithm='none')

        raise ValueError("Unsupported algorithm")

